<script setup lang="ts">
import {computed, onMounted, ref} from "vue"
import type {BusinessAvailabilityExceptionRequestDTO, BusinessAvailabilityExceptionResponseDTO, BusinessOfferingResponseDTO} from "../../../contracts/index.ts"
import {userShellApi} from "../api/userShellApi.ts"
import AppDialog from "../components/AppDialog.vue"
import AppButton from "../components/AppButton.vue"
import AppFormField from "../components/AppFormField.vue"
import AppFormFooter from "../components/AppFormFooter.vue"
import AppStatus from "../components/AppStatus.vue"
import CollectionToolbar from "../components/CollectionToolbar.vue"
import SurfaceRow from "../components/SurfaceRow.vue"
import {confirmAction} from "../composables/useActionDialog.ts"
import {formatDateTime} from "../../../services/formatters.ts"

const items = ref<BusinessAvailabilityExceptionResponseDTO[]>([])
const offerings = ref<BusinessOfferingResponseDTO[]>([])
const form = ref<BusinessAvailabilityExceptionRequestDTO | null>(null)
const editingId = ref<number | null>(null)
const isLoading = ref(true)
const isSaving = ref(false)
const error = ref("")
const feedback = ref("")
const selectedExceptionId = ref<number | null>(null)
const selectedException = computed(() => items.value.find((item) => item.id === selectedExceptionId.value) ?? null)
const emptyForm = (): BusinessAvailabilityExceptionRequestDTO => ({businessOfferingId: offerings.value[0]?.id ?? 0, exceptionType: "BLOCK", startAt: "", endAt: "", replacementCapacity: 1, replacementStartTimeLocal: "09:00", replacementEndTimeLocal: "17:00", reason: ""})
const formatDate = (value: string) => formatDateTime(value, "Unknown time")
const load = async () => { isLoading.value = true; error.value = ""; try { const [exceptionResponse, offeringResponse] = await Promise.all([userShellApi.getBusinessAvailabilityExceptions(), userShellApi.getBusinessOfferings()]); items.value = exceptionResponse.items; offerings.value = offeringResponse.items } catch { error.value = "Could not load availability exceptions." } finally { isLoading.value = false } }
const beginCreate = () => { editingId.value = null; form.value = emptyForm(); feedback.value = "" }
const beginEdit = (item: BusinessAvailabilityExceptionResponseDTO) => { editingId.value = item.id; form.value = {businessOfferingId: item.businessOfferingId, exceptionType: item.exceptionType, startAt: item.startAt.slice(0, 16), endAt: item.endAt.slice(0, 16), replacementCapacity: item.replacementCapacity, replacementStartTimeLocal: item.replacementStartTimeLocal, replacementEndTimeLocal: item.replacementEndTimeLocal, reason: item.reason}; feedback.value = "" }
const save = async () => { if (!form.value || !form.value.businessOfferingId || !form.value.startAt || !form.value.endAt) return; isSaving.value = true; error.value = ""; const request = {...form.value, startAt: new Date(form.value.startAt).toISOString(), endAt: new Date(form.value.endAt).toISOString()}; try { if (editingId.value) await userShellApi.updateBusinessAvailabilityException(editingId.value, request); else await userShellApi.createBusinessAvailabilityException(request); form.value = null; feedback.value = "Availability exception saved."; await load() } catch { error.value = "Could not save this exception." } finally { isSaving.value = false } }
const remove = async (item: BusinessAvailabilityExceptionResponseDTO) => { if (!await confirmAction("Delete this availability exception?", "Delete exception")) return; isSaving.value = true; error.value = ""; try { await userShellApi.deleteBusinessAvailabilityException(item.id); feedback.value = "Availability exception deleted."; await load() } catch { error.value = "Could not delete this exception." } finally { isSaving.value = false } }
onMounted(() => void load())
</script>
<style scoped>
.exceptions__workspace{display:grid;grid-template-columns:minmax(0,1fr) minmax(16rem,22rem);gap:var(--space-3);align-items:start}.exceptions__preview{display:grid;gap:var(--space-2);padding:var(--space-3);border:1px solid var(--border-subtle);border-radius:var(--radius-surface);background:var(--surface-raised);color:var(--text-muted)}.exceptions__preview h2,.exceptions__preview p{margin:0}.exceptions__preview h2{color:var(--text);font-size:var(--text-size-title)}.exceptions__preview dl{display:grid;gap:var(--space-2);margin:var(--space-2) 0}.exceptions__preview dl div{display:flex;justify-content:space-between;gap:var(--space-2);border-top:1px solid var(--border-subtle);padding-top:var(--space-2)}.exceptions__preview dt{color:var(--text-soft);font-size:var(--text-size-meta)}.exceptions__preview dd{margin:0;color:var(--text);font-size:var(--text-size-meta);font-weight:var(--text-weight-semibold)}.exceptions__preview-note{color:var(--text-soft);font-size:var(--text-size-meta);line-height:1.45}.exceptions__preview-actions{display:flex;gap:var(--space-2);flex-wrap:wrap}.exceptions__preview--empty{min-height:10rem;align-content:center}@media(max-width:860px){.exceptions__workspace{grid-template-columns:1fr}.exceptions__preview{order:2}}
</style>

<template><section class="exceptions"><header class="exceptions__header"><div><p class="exceptions__eyebrow">Business / Availability</p><h1>Exceptions</h1></div></header><CollectionToolbar title="Schedule exceptions" :count="items.length" :busy="isLoading"><template #actions><AppButton type="button" tone="primary" :disabled="offerings.length === 0" @click="beginCreate">New exception</AppButton></template></CollectionToolbar><AppStatus v-if="feedback" :message="feedback" tone="success" /><AppStatus v-if="isLoading" message="Loading availability exceptions." busy /><AppStatus v-else-if="error && !form" :message="error" tone="error" retry @retry="load" /><AppStatus v-else-if="items.length === 0 && !form" message="No availability exceptions." /><div v-else class="exceptions__workspace"><div class="exceptions__list"><SurfaceRow v-for="item in items" :key="item.id" :row="{id: String(item.id), title: `${item.businessOfferingTitle} · ${item.exceptionType}`, description: `${formatDate(item.startAt)} – ${formatDate(item.endAt)}${item.reason ? ` · ${item.reason}` : ''}`, meta: item.exceptionType === 'REPLACE_WINDOW' ? `Capacity ${item.replacementCapacity}` : 'Blocked'}" :selected="selectedExceptionId === item.id" @click="selectedExceptionId = item.id"><template #actions><AppButton type="button" tone="secondary" @click.stop="beginEdit(item)">Edit</AppButton><AppButton type="button" tone="danger" @click.stop="remove(item)">Delete</AppButton></template></SurfaceRow></div><aside v-if="selectedException" class="exceptions__preview" aria-label="Availability exception preview"><p class="exceptions__eyebrow">Selected exception</p><h2>{{ selectedException.businessOfferingTitle }}</h2><p>{{ selectedException.exceptionType === 'REPLACE_WINDOW' ? 'Replacement window' : 'Blocked window' }}</p><dl><div><dt>Start</dt><dd>{{ formatDate(selectedException.startAt) }}</dd></div><div><dt>End</dt><dd>{{ formatDate(selectedException.endAt) }}</dd></div><div><dt>Capacity</dt><dd>{{ selectedException.exceptionType === 'REPLACE_WINDOW' ? selectedException.replacementCapacity : 'Unavailable' }}</dd></div></dl><p v-if="selectedException.reason" class="exceptions__preview-note">{{ selectedException.reason }}</p><p class="exceptions__preview-note">The backend resolves exception precedence and booking conflicts.</p><div class="exceptions__preview-actions"><AppButton type="button" tone="secondary" @click="beginEdit(selectedException)">Edit exception</AppButton><AppButton type="button" tone="danger" @click="remove(selectedException)">Delete exception</AppButton></div></aside><aside v-else class="exceptions__preview exceptions__preview--empty" aria-label="Availability exception preview"><p class="exceptions__eyebrow">Preview</p><h2>Select an exception</h2><p>Inspect the affected schedule window without leaving the collection.</p></aside></div><AppDialog :open="form !== null" :title="editingId ? 'Edit exception' : 'New exception'" layout="workspace" @close="form = null"><form class="exceptions__form" @submit.prevent="save"><AppFormField label="Offering" required><select v-model.number="form!.businessOfferingId" required><option v-for="offering in offerings" :key="offering.id" :value="offering.id">{{ offering.title }}</option></select></AppFormField><div class="exceptions__grid"><AppFormField label="Type"><select v-model="form!.exceptionType"><option value="BLOCK">Block</option><option value="REPLACE_WINDOW">Replace window</option></select></AppFormField><AppFormField label="Start" required><input v-model="form!.startAt" type="datetime-local" required></AppFormField><AppFormField label="End" required><input v-model="form!.endAt" type="datetime-local" required></AppFormField></div><div v-if="form!.exceptionType === 'REPLACE_WINDOW'" class="exceptions__grid"><AppFormField label="Capacity"><input v-model.number="form!.replacementCapacity" type="number" min="1"></AppFormField><AppFormField label="From"><input v-model="form!.replacementStartTimeLocal" type="time"></AppFormField><AppFormField label="To"><input v-model="form!.replacementEndTimeLocal" type="time"></AppFormField></div><AppFormField label="Reason" optional><input v-model="form!.reason" maxlength="500"></AppFormField><AppStatus v-if="error" :message="error" tone="error" /><AppFormFooter><template #secondary><AppButton type="button" tone="secondary" @click="form = null">Cancel</AppButton></template><template #primary><AppButton type="submit" tone="primary" :loading="isSaving">{{ isSaving ? "Saving" : "Save" }}</AppButton></template></AppFormFooter></form></AppDialog></section></template>

<style scoped>
.exceptions{display:grid;gap:var(--space-3);max-width:none}.exceptions__header{display:flex;align-items:end}.exceptions__eyebrow{margin:0 0 var(--space-1);color:var(--text-soft);font-size:var(--text-size-label);font-weight:var(--text-weight-semibold);letter-spacing:var(--tracking-label);text-transform:uppercase}h1{margin:0;color:var(--text);font-size:var(--text-size-page-title);letter-spacing:var(--tracking-tight)}.exceptions__list{overflow:hidden;border:1px solid var(--border-subtle);border-radius:var(--radius-surface);background:var(--surface-base)}.exceptions__list :deep(.surface-row:last-child){border-bottom:0}.exceptions__primary{border:1px solid var(--accent)!important;background:var(--accent)!important;color:var(--canvas)!important}.exceptions__danger{color:var(--danger)}.exceptions__form{display:grid;gap:var(--space-3)}.exceptions__form input,.exceptions__form select{width:100%;box-sizing:border-box;border:1px solid var(--control-border);border-radius:var(--radius-control);padding:var(--space-2);background:var(--control-bg);color:var(--text);font:inherit}.exceptions__grid{display:grid;grid-template-columns:repeat(3,1fr);gap:var(--space-2)}@media(max-width:620px){.exceptions__grid{grid-template-columns:1fr}}
</style>
